-- Name: gerar_numero_os(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.gerar_numero_os() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.numero_os = (SELECT COALESCE(MAX(numero_os), 0) + 1 FROM ordens_servico);
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.gerar_numero_os() OWNER TO postgres;

--
-- Name: log_status_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_status_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        INSERT INTO status_log (os_id, status_anterior, status_novo, alterado_por)
        VALUES (NEW.id, OLD.status, NEW.status, COALESCE(current_setting('app.current_user', TRUE), 'sistema'));
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.log_status_change() OWNER TO postgres;

--
-- Name: recalcular_valor_os(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.recalcular_valor_os() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE ordens_servico
    SET valor_total = (
        SELECT COALESCE(SUM(valor_total), 0)
        FROM os_itens
        WHERE os_id = COALESCE(NEW.os_id, OLD.os_id)
    )
    WHERE id = COALESCE(NEW.os_id, OLD.os_id);
    RETURN NULL;
END;
$$;


ALTER FUNCTION public.recalcular_valor_os() OWNER TO postgres;

