--
-- Name: vw_auditoria_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_auditoria_status AS
 SELECT sl.id,
    sl.os_id,
    os.numero_os,
    c.nome_razao_social AS cliente,
    sl.status_anterior,
    sl.status_novo,
    sl.alterado_por,
    sl.created_at AS data_alteracao
   FROM ((public.status_log sl
     JOIN public.ordens_servico os ON ((os.id = sl.os_id)))
     JOIN public.clientes c ON ((c.id = os.cliente_id)))
  ORDER BY sl.created_at DESC, sl.id DESC;


ALTER VIEW public.vw_auditoria_status OWNER TO postgres;

