COMMENT ON VIEW public.vw_auditoria_status IS 'Registro de auditoria de todas as alteracoes de status das OS';


--
-- Name: vw_dashboard_resumo; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_dashboard_resumo AS
 SELECT ( SELECT count(*) AS count
           FROM public.ordens_servico) AS total_os_geral,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Orcamento'::public.status_os)) AS os_em_orcamento,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Em Manutencao'::public.status_os)) AS os_em_manutencao,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Pronto para Retirada'::public.status_os)) AS os_prontas_retirar,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Aguardando Peca'::public.status_os)) AS os_aguardando_peca,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Finalizado'::public.status_os)) AS os_finalizadas,
    ( SELECT count(*) AS count
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Cancelado'::public.status_os)) AS os_canceladas,
    ( SELECT COALESCE(sum(ordens_servico.valor_total), (0)::numeric) AS "coalesce"
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Finalizado'::public.status_os)) AS faturamento_total,
    ( SELECT COALESCE(sum(ordens_servico.valor_total), (0)::numeric) AS "coalesce"
           FROM public.ordens_servico
          WHERE ((ordens_servico.status = 'Finalizado'::public.status_os) AND (ordens_servico.data_saida >= date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone)))) AS faturamento_mes_atual,
    ( SELECT COALESCE(sum(ordens_servico.valor_total), (0)::numeric) AS "coalesce"
           FROM public.ordens_servico
          WHERE ((ordens_servico.status = 'Finalizado'::public.status_os) AND (ordens_servico.data_saida >= date_trunc('week'::text, (CURRENT_DATE)::timestamp with time zone)))) AS faturamento_semana_atual,
    ( SELECT count(*) AS count
           FROM public.clientes
          WHERE (clientes.status = 'Ativo'::public.status_cliente)) AS clientes_ativos,
    ( SELECT count(*) AS count
           FROM public.tecnicos
          WHERE (tecnicos.status = 'Ativo'::public.status_tecnico)) AS tecnicos_ativos,
    ( SELECT COALESCE(round(avg(ordens_servico.valor_total), 2), (0)::numeric) AS "coalesce"
           FROM public.ordens_servico
          WHERE (ordens_servico.status = 'Finalizado'::public.status_os)) AS ticket_medio_geral;


ALTER VIEW public.vw_dashboard_resumo OWNER TO postgres;

--
-- Name: vw_defeitos_categorizados; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_defeitos_categorizados AS
 SELECT
        CASE
            WHEN ((lower(defeito_relatado) ~~ '%tela%'::text) OR (lower(defeito_relatado) ~~ '%display%'::text) OR (lower(defeito_relatado) ~~ '%video%'::text) OR (lower(defeito_relatado) ~~ '%imagem%'::text)) THEN 'Tela / Video'::text
            WHEN ((lower(defeito_relatado) ~~ '%teclado%'::text) OR (lower(defeito_relatado) ~~ '%tecla%'::text)) THEN 'Teclado'::text
            WHEN ((lower(defeito_relatado) ~~ '%bateria%'::text) OR (lower(defeito_relatado) ~~ '%carrega%'::text) OR (lower(defeito_relatado) ~~ '%fonte%'::text) OR (lower(defeito_relatado) ~~ '%energia%'::text)) THEN 'Bateria / Carregador'::text
            WHEN ((lower(defeito_relatado) ~~ '%som%'::text) OR (lower(defeito_relatado) ~~ '%audio%'::text) OR (lower(defeito_relatado) ~~ '%auto falante%'::text)) THEN 'Audio / Som'::text
            WHEN ((lower(defeito_relatado) ~~ '%lento%'::text) OR (lower(defeito_relatado) ~~ '%travando%'::text) OR (lower(defeito_relatado) ~~ '%congelando%'::text)) THEN 'Desempenho Lento'::text
            WHEN ((lower(defeito_relatado) ~~ '%formatar%'::text) OR (lower(defeito_relatado) ~~ '%formata%'::text) OR (lower(defeito_relatado) ~~ '%windows%'::text) OR (lower(defeito_relatado) ~~ '%sistema%'::text) OR (lower(defeito_relatado) ~~ '%os%'::text)) THEN 'Software / Sistema Operacional'::text
            WHEN ((lower(defeito_relatado) ~~ '%virus%'::text) OR (lower(defeito_relatado) ~~ '%malware%'::text) OR (lower(defeito_relatado) ~~ '%antivirus%'::text)) THEN 'Virus / Malware'::text
            WHEN ((lower(defeito_relatado) ~~ '%hd%'::text) OR (lower(defeito_relatado) ~~ '%disco%'::text) OR (lower(defeito_relatado) ~~ '%ssd%'::text) OR (lower(defeito_relatado) ~~ '%armazenamento%'::text)) THEN 'Armazenamento (HD/SSD)'::text
            WHEN ((lower(defeito_relatado) ~~ '%memoria%'::text) OR (lower(defeito_relatado) ~~ '%ram%'::text)) THEN 'Memoria RAM'::text
            WHEN ((lower(defeito_relatado) ~~ '%usb%'::text) OR (lower(defeito_relatado) ~~ '%porta%'::text) OR (lower(defeito_relatado) ~~ '%conector%'::text)) THEN 'Portas / Conectores'::text
            WHEN ((lower(defeito_relatado) ~~ '%wifi%'::text) OR (lower(defeito_relatado) ~~ '%rede%'::text) OR (lower(defeito_relatado) ~~ '%internet%'::text) OR (lower(defeito_relatado) ~~ '%conexao%'::text)) THEN 'Rede / WiFi'::text
            ELSE 'Outros'::text
        END AS categoria_defeito,
    count(*) AS quantidade
   FROM public.ordens_servico
  WHERE ((defeito_relatado IS NOT NULL) AND (TRIM(BOTH FROM defeito_relatado) <> ''::text))
  GROUP BY
        CASE
            WHEN ((lower(defeito_relatado) ~~ '%tela%'::text) OR (lower(defeito_relatado) ~~ '%display%'::text) OR (lower(defeito_relatado) ~~ '%video%'::text) OR (lower(defeito_relatado) ~~ '%imagem%'::text)) THEN 'Tela / Video'::text
            WHEN ((lower(defeito_relatado) ~~ '%teclado%'::text) OR (lower(defeito_relatado) ~~ '%tecla%'::text)) THEN 'Teclado'::text
            WHEN ((lower(defeito_relatado) ~~ '%bateria%'::text) OR (lower(defeito_relatado) ~~ '%carrega%'::text) OR (lower(defeito_relatado) ~~ '%fonte%'::text) OR (lower(defeito_relatado) ~~ '%energia%'::text)) THEN 'Bateria / Carregador'::text
            WHEN ((lower(defeito_relatado) ~~ '%som%'::text) OR (lower(defeito_relatado) ~~ '%audio%'::text) OR (lower(defeito_relatado) ~~ '%auto falante%'::text)) THEN 'Audio / Som'::text
            WHEN ((lower(defeito_relatado) ~~ '%lento%'::text) OR (lower(defeito_relatado) ~~ '%travando%'::text) OR (lower(defeito_relatado) ~~ '%congelando%'::text)) THEN 'Desempenho Lento'::text
            WHEN ((lower(defeito_relatado) ~~ '%formatar%'::text) OR (lower(defeito_relatado) ~~ '%formata%'::text) OR (lower(defeito_relatado) ~~ '%windows%'::text) OR (lower(defeito_relatado) ~~ '%sistema%'::text) OR (lower(defeito_relatado) ~~ '%os%'::text)) THEN 'Software / Sistema Operacional'::text
            WHEN ((lower(defeito_relatado) ~~ '%virus%'::text) OR (lower(defeito_relatado) ~~ '%malware%'::text) OR (lower(defeito_relatado) ~~ '%antivirus%'::text)) THEN 'Virus / Malware'::text
            WHEN ((lower(defeito_relatado) ~~ '%hd%'::text) OR (lower(defeito_relatado) ~~ '%disco%'::text) OR (lower(defeito_relatado) ~~ '%ssd%'::text) OR (lower(defeito_relatado) ~~ '%armazenamento%'::text)) THEN 'Armazenamento (HD/SSD)'::text
            WHEN ((lower(defeito_relatado) ~~ '%memoria%'::text) OR (lower(defeito_relatado) ~~ '%ram%'::text)) THEN 'Memoria RAM'::text
            WHEN ((lower(defeito_relatado) ~~ '%usb%'::text) OR (lower(defeito_relatado) ~~ '%porta%'::text) OR (lower(defeito_relatado) ~~ '%conector%'::text)) THEN 'Portas / Conectores'::text
            WHEN ((lower(defeito_relatado) ~~ '%wifi%'::text) OR (lower(defeito_relatado) ~~ '%rede%'::text) OR (lower(defeito_relatado) ~~ '%internet%'::text) OR (lower(defeito_relatado) ~~ '%conexao%'::text)) THEN 'Rede / WiFi'::text
            ELSE 'Outros'::text
        END
  ORDER BY (count(*)) DESC;


ALTER VIEW public.vw_defeitos_categorizados OWNER TO postgres;

--
-- Name: vw_defeitos_mais_comuns; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_defeitos_mais_comuns AS
 SELECT palavra_chave,
    ocorrencias
   FROM ( SELECT TRIM(BOTH FROM lower(regexp_split_to_table(ordens_servico.defeito_relatado, '[\s,.;:!?]+'::text))) AS palavra_chave,
            count(*) AS ocorrencias
           FROM public.ordens_servico
          WHERE ((ordens_servico.defeito_relatado IS NOT NULL) AND (TRIM(BOTH FROM ordens_servico.defeito_relatado) <> ''::text))
          GROUP BY (TRIM(BOTH FROM lower(regexp_split_to_table(ordens_servico.defeito_relatado, '[\s,.;:!?]+'::text))))) sub
  WHERE ((length(palavra_chave) > 3) AND (ocorrencias >= 2))
  ORDER BY ocorrencias DESC
 LIMIT 30;


ALTER VIEW public.vw_defeitos_mais_comuns OWNER TO postgres;

--
-- Name: vw_faturamento_mensal; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_faturamento_mensal AS
 SELECT to_char(data_saida, 'YYYY-MM'::text) AS ano_mes,
    to_char(data_saida, 'Mon/YYYY'::text) AS mes_ano,
    (EXTRACT(year FROM data_saida))::integer AS ano,
    (EXTRACT(month FROM data_saida))::integer AS mes,
    count(*) AS total_os,
    sum(valor_total) AS faturamento_total,
    round(avg(valor_total), 2) AS ticket_medio
   FROM public.ordens_servico
  WHERE ((status = 'Finalizado'::public.status_os) AND (data_saida IS NOT NULL))
  GROUP BY (to_char(data_saida, 'YYYY-MM'::text)), (to_char(data_saida, 'Mon/YYYY'::text)), ((EXTRACT(year FROM data_saida))::integer), ((EXTRACT(month FROM data_saida))::integer)
  ORDER BY ((EXTRACT(year FROM data_saida))::integer) DESC, ((EXTRACT(month FROM data_saida))::integer) DESC;


ALTER VIEW public.vw_faturamento_mensal OWNER TO postgres;

--
-- Name: vw_faturamento_semanal; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_faturamento_semanal AS
 SELECT (EXTRACT(year FROM data_saida))::integer AS ano,
    (EXTRACT(week FROM data_saida))::integer AS semana,
    (date_trunc('week'::text, data_saida))::date AS inicio_semana,
    count(*) AS total_os,
    sum(valor_total) AS faturamento_total
   FROM public.ordens_servico
  WHERE ((status = 'Finalizado'::public.status_os) AND (data_saida IS NOT NULL))
  GROUP BY ((EXTRACT(year FROM data_saida))::integer), ((EXTRACT(week FROM data_saida))::integer), ((date_trunc('week'::text, data_saida))::date)
  ORDER BY ((EXTRACT(year FROM data_saida))::integer) DESC, ((EXTRACT(week FROM data_saida))::integer) DESC;


ALTER VIEW public.vw_faturamento_semanal OWNER TO postgres;

--
-- Name: vw_historico_cliente; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_historico_cliente AS
 SELECT c.id AS cliente_id,
    c.nome_razao_social AS cliente,
    c.cpf_cnpj AS documento_cliente,
    os.id AS os_id,
    os.numero_os,
    os.data_entrada,
    COALESCE(os.data_saida, os.data_entrada) AS data_servico,
    t.nome AS tecnico_responsavel,
    os.status AS status_os,
    string_agg(
        CASE
            WHEN (oi.descricao IS NOT NULL) THEN ((((oi.descricao)::text || ' (x'::text) || (oi.quantidade)::text) || ')'::text)
            ELSE NULL::text
        END, '; '::text ORDER BY oi.id) AS servicos_realizados,
    os.valor_total AS valor_cobrado
   FROM (((public.ordens_servico os
     JOIN public.clientes c ON ((c.id = os.cliente_id)))
     LEFT JOIN public.tecnicos t ON ((t.id = os.tecnico_id)))
     LEFT JOIN public.os_itens oi ON ((oi.os_id = os.id)))
  GROUP BY c.id, c.nome_razao_social, c.cpf_cnpj, os.id, os.numero_os, os.data_entrada, os.data_saida, t.nome, os.status, os.valor_total
  ORDER BY os.data_entrada DESC, os.numero_os DESC;


ALTER VIEW public.vw_historico_cliente OWNER TO postgres;

--
-- Name: VIEW vw_historico_cliente; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.vw_historico_cliente IS 'Retorna o historico completo de ordens de servico por cliente';


--
-- Name: vw_os_detalhada; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_os_detalhada AS
 SELECT os.id,
    os.numero_os,
    c.nome_razao_social AS cliente_nome,
    c.cpf_cnpj AS cliente_doc,
    c.telefone AS cliente_telefone,
    c.whatsapp AS cliente_whatsapp,
    c.email AS cliente_email,
    t.nome AS tecnico_nome,
    t.especialidade AS tecnico_especialidade,
    os.marca,
    os.modelo,
    os.numero_serie,
    os.senha_bios,
    os.defeito_relatado,
    os.laudo_tecnico,
    os.status,
    os.data_entrada,
    os.data_saida,
    os.valor_total,
    cl.tela,
    cl.teclado,
    cl.teclas_especificar,
    cl.camera,
    cl.som,
    cl.rede_rj45,
    cl.rede_wifi,
    cl.usb,
    cl.microfone,
    cl.touchpad,
    cl.bateria,
    cl.tempo_autonomia,
    cl.carcaca,
    cl.observacoes
   FROM (((public.ordens_servico os
     JOIN public.clientes c ON ((c.id = os.cliente_id)))
     LEFT JOIN public.tecnicos t ON ((t.id = os.tecnico_id)))
     LEFT JOIN public.checklists cl ON ((cl.os_id = os.id)));


ALTER VIEW public.vw_os_detalhada OWNER TO postgres;

--
-- Name: VIEW vw_os_detalhada; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.vw_os_detalhada IS 'Visao completa de cada OS com dados do cliente, tecnico e checklist';


