CREATE VIEW public.vw_os_itens_detalhado AS
 SELECT oi.id,
    oi.os_id,
    os.numero_os,
    oi.descricao,
    oi.tipo,
    oi.quantidade,
    oi.valor_unitario,
    oi.valor_total
   FROM (public.os_itens oi
     JOIN public.ordens_servico os ON ((os.id = oi.os_id)))
  ORDER BY oi.os_id, oi.id;


ALTER VIEW public.vw_os_itens_detalhado OWNER TO postgres;

--
-- Name: VIEW vw_os_itens_detalhado; Type: COMMENT; Schema: public; Owner: postgres
