COMMENT ON VIEW public.vw_os_itens_detalhado IS 'Itens de servico e produto vinculados a cada OS';


--
-- Name: vw_painel_status_geral; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_painel_status_geral AS
 SELECT status,
    count(*) AS quantidade,
    sum(valor_total) AS valor_total_acumulado
   FROM public.ordens_servico
  GROUP BY status
  ORDER BY
        CASE status
            WHEN 'Orcamento'::public.status_os THEN 1
            WHEN 'Aprovado'::public.status_os THEN 2
            WHEN 'Em Manutencao'::public.status_os THEN 3
            WHEN 'Aguardando Peca'::public.status_os THEN 4
            WHEN 'Pronto para Retirada'::public.status_os THEN 5
            WHEN 'Finalizado'::public.status_os THEN 6
            WHEN 'Cancelado'::public.status_os THEN 7
            ELSE NULL::integer
        END;


ALTER VIEW public.vw_painel_status_geral OWNER TO postgres;

--
-- Name: vw_produtividade_tecnico; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_produtividade_tecnico AS
 SELECT t.id AS tecnico_id,
    t.nome AS tecnico,
    t.especialidade,
    count(*) AS total_os_finalizadas,
    sum(os.valor_total) AS valor_total_gerado,
    round(avg(os.valor_total), 2) AS ticket_medio_tecnico,
    round(avg((EXTRACT(epoch FROM (COALESCE((os.data_saida)::timestamp with time zone, now()) - (os.data_entrada)::timestamp with time zone)) / (86400)::numeric)), 1) AS dias_medio_por_os
   FROM (public.ordens_servico os
     JOIN public.tecnicos t ON ((t.id = os.tecnico_id)))
  WHERE (os.status = 'Finalizado'::public.status_os)
  GROUP BY t.id, t.nome, t.especialidade
  ORDER BY (sum(os.valor_total)) DESC;


ALTER VIEW public.vw_produtividade_tecnico OWNER TO postgres;

--
-- Name: vw_produtividade_tecnico_periodo; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_produtividade_tecnico_periodo AS
 SELECT t.id AS tecnico_id,
    t.nome AS tecnico,
    (date_trunc('month'::text, os.data_saida))::date AS mes_referencia,
    count(*) AS os_finalizadas,
    sum(os.valor_total) AS valor_gerado
   FROM (public.ordens_servico os
     JOIN public.tecnicos t ON ((t.id = os.tecnico_id)))
  WHERE ((os.status = 'Finalizado'::public.status_os) AND (os.data_saida IS NOT NULL))
  GROUP BY t.id, t.nome, (date_trunc('month'::text, os.data_saida))
  ORDER BY ((date_trunc('month'::text, os.data_saida))::date) DESC, (sum(os.valor_total)) DESC;


ALTER VIEW public.vw_produtividade_tecnico_periodo OWNER TO postgres;

--
-- Name: vw_servicos_mais_recorrentes; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_servicos_mais_recorrentes AS
 SELECT oi.descricao,
    oi.tipo,
    count(*) AS vezes_realizado,
    sum(oi.quantidade) AS total_itens,
    sum(oi.valor_total) AS receita_gerada,
    round(avg(oi.valor_unitario), 2) AS valor_medio
   FROM (public.os_itens oi
     JOIN public.ordens_servico os ON ((os.id = oi.os_id)))
  WHERE (os.status = 'Finalizado'::public.status_os)
  GROUP BY oi.descricao, oi.tipo
  ORDER BY (count(*)) DESC
 LIMIT 20;


ALTER VIEW public.vw_servicos_mais_recorrentes OWNER TO postgres;

--
-- Name: vw_status_os_tempo_real; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_status_os_tempo_real AS
 SELECT status,
    count(*) AS quantidade,
    sum(valor_total) AS valor_em_aberto,
    round((((count(*))::numeric * 100.0) / sum(count(*)) OVER ()), 1) AS percentual
   FROM public.ordens_servico
  WHERE ((status <> 'Finalizado'::public.status_os) AND (status <> 'Cancelado'::public.status_os))
  GROUP BY status
  ORDER BY
        CASE status
            WHEN 'Orcamento'::public.status_os THEN 1
            WHEN 'Aprovado'::public.status_os THEN 2
            WHEN 'Em Manutencao'::public.status_os THEN 3
            WHEN 'Aguardando Peca'::public.status_os THEN 4
            WHEN 'Pronto para Retirada'::public.status_os THEN 5
            ELSE 6
        END;


ALTER VIEW public.vw_status_os_tempo_real OWNER TO postgres;

